// Buchungsdaten normalisieren (Website oder WhatsApp)
const body = $input.first().json.body || $input.first().json;

let schuelerName = body.name || body.schuelerName || body.Name || '';
let telefon = body.telefon || body.phone || body.Telefon || '';
let email = body.email || body.Email || '';
let wunschDatum = body.datum || body.date || body.Datum || '';
let wunschZeit = body.zeit || body.time || body.Zeit || body.Uhrzeit || '';
let terminArt = body.art || body.type || body.Art || 'Fahrstunde';
let fahrlehrerWunsch = body.fahrlehrer || body.instructor || body.Fahrlehrer || '';
let nachricht = body.nachricht || body.message || body.Nachricht || '';
let fuehrerscheinKlasse = body.klasse || body.Klasse || body.license_class || 'B';

// Telefonnummer bereinigen
telefon = telefon.toString().replace(/[\s\-\/\(\)]/g, '');
if (telefon && !telefon.startsWith('+')) {
  telefon = '+49' + telefon.replace(/^0/, '');
}

// Buchungs-ID generieren
const buchungsId = 'BK-' + Date.now().toString(36).toUpperCase();

return [{
  json: {
    buchungsId,
    schuelerName,
    telefon,
    email,
    wunschDatum,
    wunschZeit,
    terminArt,
    fahrlehrerWunsch,
    fuehrerscheinKlasse,
    nachricht,
    eingang: new Date().toISOString(),
    status: 'neu'
  }
}];

// Zustaendigen Fahrlehrer bestimmen
const data = $input.first().json;
if (!data) throw new Error('Keine Buchungsdaten empfangen');

const wunschLehrer = data.fahrlehrerWunsch || '';

// Fahrlehrer-Zuordnung (pro Kunde konfigurierbar)
let fahrlehrer = {};
try {
  fahrlehrer = JSON.parse($env.FAHRLEHRER_CONFIG || '{}');
} catch(e) {
  // Falls FAHRLEHRER_CONFIG kein gueltiges JSON ist, leeres Objekt verwenden
  fahrlehrer = {};
}

// Beispiel FAHRLEHRER_CONFIG:
// {"default":"+491721234567","Schmidt":"+491721234567","Klein":"+491739876543"}

let lehrerTelefon = fahrlehrer.default || $env.FAHRLEHRER_TELEFON || '';
let lehrerName = 'Zustaendiger Fahrlehrer';

if (wunschLehrer) {
  for (const [name, tel] of Object.entries(fahrlehrer)) {
    if (name === 'default') continue;
    if (name.toLowerCase() === wunschLehrer.toLowerCase() ||
        wunschLehrer.toLowerCase().includes(name.toLowerCase())) {
      lehrerTelefon = tel;
      lehrerName = name;
      break;
    }
  }
}

if (!lehrerTelefon) {
  lehrerTelefon = $env.FAHRLEHRER_TELEFON || $env.FAHRSCHULINHABER_TELEFON || '';
}

return [{
  json: {
    ...data,
    lehrerTelefon,
    lehrerName
  }
}];

