// Fahrlehrer-Antwort auswerten
const body = $input.first().json.body || $input.first().json;
const messageBody = (body.Body || body.body || '').trim().toUpperCase();
const from = (body.From || body.from || '').replace('whatsapp:', '').trim();

// BESTAETIGEN BK-XXXXX
if (messageBody.startsWith('BESTAETIGEN') || messageBody.startsWith('BESTÄTIGEN')) {
  const buchungsId = messageBody.split(' ')[1] || '';
  return [{
    json: {
      action: 'bestaetigt',
      buchungsId,
      lehrerTelefon: from,
      alternativDatum: '',
      alternativZeit: ''
    }
  }];
}

// ALTERNATIV BK-XXXXX 29.03.2026 14:00
if (messageBody.startsWith('ALTERNATIV')) {
  const parts = messageBody.split(' ');
  const buchungsId = parts[1] || '';
  const altDatum = parts[2] || '';
  const altZeit = parts[3] || '';
  return [{
    json: {
      action: 'alternativ',
      buchungsId,
      lehrerTelefon: from,
      alternativDatum: altDatum,
      alternativZeit: altZeit
    }
  }];
}

// ABLEHNEN BK-XXXXX
if (messageBody.startsWith('ABLEHNEN')) {
  const buchungsId = messageBody.split(' ')[1] || '';
  return [{
    json: {
      action: 'abgelehnt',
      buchungsId,
      lehrerTelefon: from,
      alternativDatum: '',
      alternativZeit: ''
    }
  }];
}

return [{ json: { action: 'unbekannt', lehrerTelefon: from, message: messageBody } }];

